#[test]
fn test_fire_at_exact_target_blocks_frequency_5() {
    // start_block=100, frequency=5, num_calls=3
    // Should fire at blocks 100, 105, 110
    let call = create_test_call(100, 5, 3);

    // Target blocks should return Some(index)
    assert_eq!(call.should_fire_at_block(100), Some(0)); // Index 0
    assert_eq!(call.should_fire_at_block(105), Some(1)); // Index 1
    assert_eq!(call.should_fire_at_block(110), Some(2)); // Index 2

    // Block 115 would be index 3, but num_calls=3, so out of bo

    assert_eq!(call.should_fire_at_block(105), Some(1));
}

