#[test]
fn test_replace_calls_replaces_non_empty_state() {
    let state = SchedulerServiceState::default();
    state.add_call(1, create_test_call(100, 5, 3));
    state.add_call(2, create_test_call(200, 10, 2));
    assert_eq!(state.calls.len(), 2);

    state.replace_calls(vec![(42, create_test_call(300, 1, 4))]);

    assert_eq!(state.calls.len(), 1);
    assert!(state.calls.get(&1).is_none());
    assert!(state.calls.get(&2).is_none());
    assert!(state.calls.get(&42).is_some());
}

